#include <bits/stdc++.h>
using namespace std;

const int N=3e5+5;

int t,n,m,f[N],col[N];
bool b[N];
vector<int> g[N];

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        f[fy]=fx;
}

void dfs(int x,int fa){
    b[x]=1;
    int len=g[x].size();
    for(int i=0;i<len;i++){
        if(!b[g[x][i]])
            dfs(g[x][i],x);
        else if(g[x][i]!=fa)
            merge(x,g[x][i]);
    }
}

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d",&n,&m);
        for(int i=0;i<=n;i++)
            g[i].clear(),f[i]=i,b[i]=col[i]=0;
        for(int i=1,u,v;i<=m;i++){
            scanf("%d%d",&u,&v);
            g[u].push_back(v);
            g[v].push_back(u);
        }
        for(int i=1;i<=n;i++)
            g[0].push_back(i);
        dfs(0,-1);
        for(int i=1,k=0;i<=n;i++)
            if(!col[father(i)])
                col[father(i)]=k+1,k=(k+1)%3;
        vector<int> q[3];
        for(int i=1;i<=n;i++)
            q[col[father(i)]-1].push_back(i);
        for(int i=0;i<3;i++){
            printf("%d ",q[i].size());
            for(int j=0;j<q[i].size();j++)
                printf("%d ",q[i][j]);
            if(i<3)
            	puts("");
        }
    }
    return 0;
}
